const navbar=document.getElementById("navbar"),hamburger=document.getElementById("hamburger"),navLinks=document.getElementById("navLinks");window.addEventListener("scroll",()=>{window.scrollY>60?navbar.classList.add("scrolled"):navbar.classList.remove("scrolled")}),hamburger.addEventListener("click",()=>{hamburger.classList.toggle("open"),navLinks.classList.toggle("open"),document.body.style.overflow=navLinks.classList.contains("open")?"hidden":""}),navLinks.querySelectorAll(".nav-link").forEach(e=>{e.addEventListener("click",()=>{hamburger.classList.remove("open"),navLinks.classList.remove("open"),document.body.style.overflow=""})});const sections=document.querySelectorAll("section[id]");window.addEventListener("scroll",()=>{let e="";sections.forEach(n=>{const t=n.offsetTop-120;window.scrollY>=t&&(e=n.getAttribute("id"))}),document.querySelectorAll(".nav-link").forEach(n=>{n.classList.remove("active"),n.getAttribute("href")===`#${e}`&&n.classList.add("active")})});